PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  email TEXT NOT NULL UNIQUE,
  password_hash TEXT NOT NULL,
  created_at TEXT NOT NULL
, role TEXT NOT NULL DEFAULT 'user');
CREATE TABLE sessions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  token TEXT NOT NULL UNIQUE,
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE collections (
  id TEXT PRIMARY KEY,                 
  name TEXT NOT NULL,                  
  tagline TEXT,
  description TEXT,
  badge TEXT,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
, specs_json TEXT DEFAULT '[]', documents_json TEXT DEFAULT '[]', reviews_json TEXT DEFAULT '[]', shipping_md TEXT DEFAULT '', isolates_json TEXT DEFAULT '[]', terpenes_json TEXT DEFAULT '[]', images_json TEXT DEFAULT '[]');
CREATE TABLE flavor_profiles (
  id TEXT PRIMARY KEY,                 
  collection_id TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,           
  name TEXT NOT NULL,                  
  flavor_type TEXT,
  flavor_category TEXT,
  description TEXT,
  mood TEXT,
  dominant_terpenes TEXT,              
  flavor_aroma TEXT,                   
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (collection_id) REFERENCES collections(id) ON DELETE CASCADE
);
CREATE TABLE flavor_profile_images (
  id TEXT PRIMARY KEY,                 
  profile_id TEXT NOT NULL,
  url TEXT NOT NULL,
  alt TEXT,
  kind TEXT NOT NULL DEFAULT 'gallery', 
  sort_order INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (profile_id) REFERENCES flavor_profiles(id) ON DELETE CASCADE
);
CREATE TABLE flavor_profile_documents (
  id TEXT PRIMARY KEY,                 
  profile_id TEXT NOT NULL,
  title TEXT NOT NULL,
  url TEXT NOT NULL,
  doc_type TEXT NOT NULL DEFAULT 'other', 
  sort_order INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (profile_id) REFERENCES flavor_profiles(id) ON DELETE CASCADE
);
CREATE TABLE collection_sample_profiles (
  id TEXT PRIMARY KEY,
  collection_id TEXT NOT NULL,
  profile_id TEXT NOT NULL,
  sort_order INTEGER NOT NULL DEFAULT 0,
  is_active INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (collection_id) REFERENCES collections(id) ON DELETE CASCADE,
  
  UNIQUE (collection_id, profile_id)
);
CREATE TABLE blog_posts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    title TEXT NOT NULL,
    message TEXT NOT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    image_url TEXT,
    attachment_url TEXT
);
CREATE TABLE purchases (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    items TEXT NOT NULL, 
    total_amount DECIMAL(10, 2) NOT NULL,
    purchased_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    stripe_payment_id TEXT,
    FOREIGN KEY (user_id) REFERENCES users(id)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_sessions_token ON sessions(token);
CREATE INDEX idx_sessions_user_id ON sessions(user_id);
CREATE INDEX idx_flavor_profiles_collection
  ON flavor_profiles(collection_id, sort_order);
CREATE INDEX idx_profile_images_profile
  ON flavor_profile_images(profile_id, sort_order);
CREATE INDEX idx_profile_docs_profile
  ON flavor_profile_documents(profile_id, sort_order);
CREATE UNIQUE INDEX idx_flavor_profiles_id_collection
  ON flavor_profiles(id, collection_id);
CREATE INDEX idx_collection_sample_profiles_collection
  ON collection_sample_profiles(collection_id, is_active, sort_order, created_at);
